from nltk import pos_tag

def get_deps(tokens):
    tagged_tokens = pos_tag(tokens)
    deps = []
    for idx, (token, head) in enumerate(tagged_tokens):
        if head == 'N' and idx == 0:
            deps.append((1, 0))
        elif head == 'N' and idx == 1:
            deps.append((1, 2))
        elif head == 'N' and idx == 2:
            deps.append((2, 3))
        elif head == 'N' and idx == 3:
            deps.append((3, 4))
    return deps
