def schedule_pods(pods, nodes):
    # Initialize a dictionary to store the assignment of pods to nodes
    assignment = {}

    # Sort the pods and nodes by their cpu and mem requirements
    pods.sort(key=lambda x: (x['cpu'], x['mem']), reverse=False)
    nodes.sort(key=lambda x: (x['cpu'], x['mem']), reverse=False)

    # Iterate over the sorted pods
    for pod in pods:
        # Assign the pod to the first node that can accommodate it
        for node in nodes:
            if pod['cpu'] <= node['cpu'] and pod['mem'] <= node['mem']:
                assignment[pod['name']] = node['name']
                break

    return assignment
